class CastedLinear(nn.Module):
    def __init__(self, in_dim: int, out_dim: int):
        super().__init__()
        # Keep per-row magnitude in a cheap vector so the large matrix can stay near unit RMS for export.
        weight = nn.Linear(in_dim, out_dim, bias=False).weight.astype(mx.float32)
        row_rms = mx.sqrt(mx.mean(weight * weight, axis=1))
        safe_row_rms = mx.where(row_rms > 0.0, row_rms, mx.ones_like(row_rms))
        self.weight = weight / safe_row_rms[:, None]
        self.out_scale = safe_row_rms.astype(mx.float32)

    def __call__(self, x: mx.array) -> mx.array:
        scaled_weight = self.weight.astype(x.dtype) * self.out_scale.astype(x.dtype)[:, None]
        return x @ scaled_weight.T


def rebalance_factorized_linear_rows(params: dict[str, mx.array]) -> None:
    for key, weight in list(params.items()):
        if not key.endswith(".weight") or weight.ndim != 2:
            continue
        scale_key = f"{key[:-len('weight')]}out_scale"
        if scale_key not in params:
            continue
        # Preserve the layer function while pushing row norms back into the small scale vector.
        weight_f32 = weight.astype(mx.float32)
        row_rms = mx.sqrt(mx.mean(weight_f32 * weight_f32, axis=1))
        safe_row_rms = mx.where(row_rms > 0.0, row_rms, mx.ones_like(row_rms))
        params[key] = (weight_f32 / safe_row_rms[:, None]).astype(weight.dtype)
        params[scale_key] = (params[scale_key].astype(mx.float32) * safe_row_rms).astype(params[scale_key].dtype)


